21→const adapters: Record<string, SDUIComponentRenderer> = {
22→  heading: HeadingAdapter as SDUIComponentRenderer,
23→  text: TextAdapter as SDUIComponentRenderer,
24→  balance_display: BalanceDisplayAdapter as SDUIComponentRenderer,
25→  points_input: PointsInputAdapter as SDUIComponentRenderer,
26→  button: ButtonAdapter as SDUIComponentRenderer,
27→  link: LinkAdapter as SDUIComponentRenderer,
28→  alert: AlertAdapter as SDUIComponentRenderer,
29→  list_text_icon: ListTextIconAdapter as SDUIComponentRenderer,
30→  separator: SeparatorAdapter as SDUIComponentRenderer,
31→  icon_text_row: IconTextRowAdapter as SDUIComponentRenderer,
32→  section_heading: SectionHeadingAdapter as SDUIComponentRenderer,
33→  rich_text: RichTextAdapter as SDUIComponentRenderer,
34→  voucher_card: VoucherCardAdapter as SDUIComponentRenderer,
