 1→import type {
 2→  SDUIComponentRegistry,
 3→  SDUIComponentRenderer,
 4→} from '../models';
 5→
 6→export function createRegistry(
 7→  initial?: SDUIComponentRegistry,
 8→): SDUIComponentRegistry {
 9→  return { ...initial };
10→}
11→
12→export function registerComponent(
13→  registry: SDUIComponentRegistry,
14→  type: string,
15→  renderer: SDUIComponentRenderer,
16→): SDUIComponentRegistry {
17→  return { ...registry, [type]: renderer };
18→}
19→
20→export function getRenderer(
21→  registry: SDUIComponentRegistry,
22→  type: string,
23→): SDUIComponentRenderer | undefined {
24→  return registry[type];
25→}
26→
27→const defaultRegistry: SDUIComponentRegistry = {};
28→
29→export function getDefaultRegistry(): SDUIComponentRegistry {
30→  return defaultRegistry;
31→}
32→
33→export function registerToDefault(
34→  type: string,
35→  renderer: SDUIComponentRenderer,
36→): void {
37→  defaultRegistry[type] = renderer;
38→}
