// Immutable registry pattern
export function createRegistry(initial?: SDUIComponentRegistry): SDUIComponentRegistry {
  return { ...initial };
}

export function registerComponent(
  registry: SDUIComponentRegistry,
  type: string,
  renderer: SDUIComponentRenderer,
): SDUIComponentRegistry {
  return { ...registry, [type]: renderer };
}

export function getRenderer(
  registry: SDUIComponentRegistry,
  type: string,
): SDUIComponentRenderer | undefined {
  return registry[type];
}

// Default registry (mutated by registerToDefault)
